window.script:

using System.Linq;
using System.Windows.Forms;

// --main--

PluginManager.ExportFunction("runBox.open", (args, _) => {
    var wnd = ShellWindowManager.GetWindow("runBox");
    wnd.GetWidget("cmdTextBox").GetControl().Text = "";
    wnd.ShowWindow();

    return string.Empty;
});

PluginManager.ExportFunction("runBox.processKey", (args, vars) => {
    switch(((KeyEventArgs)ResourceManager.GetResource(args.ElementAt(0).ToString())).KeyCode){
        case Keys.Return: {
            PluginManager.GetExportedFunction("shellExecute").Invoke(new object[]{ vars.GetVariable("runBoxCmd").Trim() }, vars);
            ShellWindowManager.GetWindow("runBox").HideWindow();

            break;
        }

        case Keys.Escape: {
            ShellWindowManager.GetWindow("runBox").HideWindow();
            break;
        }
    }

    return string.Empty;
});
